groupButton1.onClick:
{{
  (async () => {
    // 1. Controle de Inatividade
    JSutils.resetInactivityTimer();

    // 2. Define o contexto para TUTOR
    await storeValue('modalContexto', {
      ...appsmith.store.modalContexto,
      entidade: 'TUTOR',
      // Mantém os dados da linha que já estava selecionada na tabela
      tutorID: TableTutor.selectedRow?.prop001_id,
      tutorNome: TableTutor.selectedRow?.prop001_nome,
      acaoTipo: "EDITAR"
    });

    // 3. Ativa a tela de Tutores
    await storeValue("telaAtiva", "TUTORES");
  })()
}}

groupButton2.onClick:
{{
  (async () => {
    // 1. Controle de Inatividade
    JSutils.resetInactivityTimer();

    // 2. Validação de Segurança
    if (!TableTutor.selectedRow?.prop001_id) {
      showAlert("Selecione um Tutor na tabela antes de acessar os Pets.", "warning");
      return;
    }

    // 3. Define o contexto completo para PET
    await storeValue('modalContexto', {
      ...appsmith.store.modalContexto,
      entidade: 'PET',
      tutorID: TableTutor.selectedRow.prop001_id,
      tutorNome: TableTutor.selectedRow.prop001_nome,
      acaoTipo: 'EDITAR',
      acaoBotao: 'ATUALIZAR' 
    });

    // 4. Busca os dados dos Pets
    const pets = await SelectPets.run();

    // 5. Seleção Automática com Tratamento de Erro (Evita o TypeError nos Selects)
    if (pets && pets.length > 0) {
      await storeValue('petSelecionado', pets[0]);
    } else {
      // IMPORTANTE: Inicializamos com strings vazias para os widgets não quebrarem
      await storeValue('petSelecionado', {
        ani002_id: null,
        ani002_nome: "",
        ani002_especie: "",
        ani002_convivio: "", // Isso evita o erro no Select1Convivio
        ani002_sexo: ""
      });
      showAlert("Este tutor ainda não possui pets cadastrados.", "info");
    }

    // 6. Reseta estados de navegação interna
    await storeValue('abaAtiva', 'Info Cadastral'); 

    // 7. Troca de tela
    await storeValue("telaAtiva", "PETS");

    // 8. Sincronização visual
    resetWidget("ListPets", true);
  })()
}}
